(function(){"use strict";function generateTOC(){const main=document.querySelector("main");if(!main)return;const headings=main.querySelectorAll("section h2, section h3");if(headings.length<3)return;const tocContainer=document.createElement("div");tocContainer.className="toc-floating";tocContainer.innerHTML='<h4>En esta guía</h4><ul id="toc-list"></ul>';const tocList=tocContainer.querySelector("#toc-list");headings.forEach((heading,index)=>{if(!heading.id){heading.id=`heading-${index}`}const level=heading.tagName==="H2"?1:2;const li=document.createElement("li");li.className=level===1?"":"toc-level-2";const a=document.createElement("a");a.href=`#${heading.id}`;a.textContent=heading.textContent;a.className="toc-link";li.appendChild(a);tocList.appendChild(li)});const breadcrumb=main.querySelector(".breadcrumb");if(breadcrumb&&breadcrumb.nextElementSibling){breadcrumb.nextElementSibling.insertAdjacentElement("afterend",tocContainer)}observeHeadings()}function observeHeadings(){const options={root:null,rootMargin:"-50% 0px -50% 0px",threshold:0};const main=document.querySelector("main");const headings=main?main.querySelectorAll("section h2, section h3"):[];const links=document.querySelectorAll(".toc-floating .toc-link");if(headings.length===0||links.length===0)return;const observer=new IntersectionObserver(entries=>{entries.forEach(entry=>{const link=Array.from(links).find(l=>l.getAttribute("href")===`#${entry.target.id}`);if(link){if(entry.isIntersecting){links.forEach(l=>l.classList.remove("active"));link.classList.add("active")}}})},options);headings.forEach(heading=>{observer.observe(heading)})}function generateShareButtons(){const articleHero=document.querySelector(".article-hero");if(!articleHero)return;const h1=articleHero.querySelector("h1");if(!h1)return;const pageTitle=h1.textContent;const pageUrl=window.location.href;const shareContainer=document.createElement("div");shareContainer.className="share-buttons";const label=document.createElement("span");label.className="share-buttons-label";label.textContent="📤 Compartir";shareContainer.appendChild(label);const linkedInBtn=document.createElement("a");linkedInBtn.className="share-btn-linkedin";linkedInBtn.href=`https://www.linkedin.com/sharing/share-offsite/?url=${encodeURIComponent(pageUrl)}`;linkedInBtn.target="_blank";linkedInBtn.rel="noopener noreferrer";linkedInBtn.title="Compartir en LinkedIn";linkedInBtn.textContent="in";shareContainer.appendChild(linkedInBtn);const twitterBtn=document.createElement("a");twitterBtn.className="share-btn-twitter";twitterBtn.href=`https://twitter.com/intent/tweet?url=${encodeURIComponent(pageUrl)}&text=${encodeURIComponent(pageTitle)}`;twitterBtn.target="_blank";twitterBtn.rel="noopener noreferrer";twitterBtn.title="Compartir en X/Twitter";twitterBtn.textContent="X";shareContainer.appendChild(twitterBtn);const facebookBtn=document.createElement("a");facebookBtn.className="share-btn-facebook";facebookBtn.href=`https://www.facebook.com/sharer/sharer.php?u=${encodeURIComponent(pageUrl)}`;facebookBtn.target="_blank";facebookBtn.rel="noopener noreferrer";facebookBtn.title="Compartir en Facebook";facebookBtn.textContent="f";shareContainer.appendChild(facebookBtn);const copyBtn=document.createElement("a");copyBtn.className="share-btn-copy";copyBtn.href="#";copyBtn.title="Copiar enlace";copyBtn.textContent="🔗";copyBtn.addEventListener("click",e=>{e.preventDefault();navigator.clipboard.writeText(pageUrl).then(()=>{const original=copyBtn.textContent;copyBtn.textContent="✓";setTimeout(()=>{copyBtn.textContent=original},2e3)})});shareContainer.appendChild(copyBtn);articleHero.insertAdjacentElement("afterend",shareContainer)}function enhanceCTAs(){const main=document.querySelector("main");if(!main)return;const sections=main.querySelectorAll("section");sections.forEach(section=>{const lastPara=section.querySelector("p:last-of-type");const link=lastPara?lastPara.querySelector('a[href*="/tools/"]'):null;if(link&&lastPara){if(!lastPara.parentElement.classList.contains("cta-container")){const ctaContainer=document.createElement("div");ctaContainer.className="cta-container";const ctaBtn=document.createElement("a");ctaBtn.className="cta-btn cta-btn-primary";ctaBtn.href=link.href;ctaBtn.innerHTML="🧮 "+link.textContent;ctaContainer.appendChild(ctaBtn);lastPara.replaceWith(ctaContainer)}}})}if(document.readyState==="loading"){document.addEventListener("DOMContentLoaded",function(){generateTOC();generateShareButtons();enhanceCTAs()})}else{generateTOC();generateShareButtons();enhanceCTAs()}})();